(window.webpackJsonp=window.webpackJsonp||[]).push([[803],{763:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val) {\\n *     this.val = val;\\n *     this.left = this.right = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number[]}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> preorderTraversal = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> stack=[],res=[]\\n  <span class=\\"hljs-keyword\\">let</span> node=root\\n  <span class=\\"hljs-keyword\\">while</span>(stack.length&gt;<span class=\\"hljs-number\\">0</span> || node){\\n    <span class=\\"hljs-keyword\\">while</span>(node){\\n      res.push(node.val)\\n      stack.push(node)\\n      node=node.left\\n    }\\n    node=stack.pop()\\n    node=node.right\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"binary-tree-preorder-traversal","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e8c\u53c9\u6811\u7684\u6839\u8282\u70b9 <code>root</code> \uff0c\u8fd4\u56de\u5b83\u8282\u70b9\u503c\u7684\xa0<strong>\u524d\u5e8f</strong><em>\xa0</em>\u904d\u5386\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/09/15/inorder_1.jpg\\" style=\\"width: 202px; height: 324px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,null,2,3]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,2,3]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = []\\n<strong>\u8f93\u51fa\uff1a</strong>[]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1]\\n<strong>\u8f93\u51fa\uff1a</strong>[1]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/09/15/inorder_5.jpg\\" style=\\"width: 202px; height: 202px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,2]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,2]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 5\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2020/09/15/inorder_4.jpg\\" style=\\"width: 202px; height: 202px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>root = [1,null,2]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,2]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u6811\u4e2d\u8282\u70b9\u6570\u76ee\u5728\u8303\u56f4 <code>[0, 100]</code> \u5185</li>\\n\\t<li><code>-100 <= Node.val <= 100</code></li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u8fdb\u9636\uff1a</strong>\u9012\u5f52\u7b97\u6cd5\u5f88\u7b80\u5355\uff0c\u4f60\u53ef\u4ee5\u901a\u8fc7\u8fed\u4ee3\u7b97\u6cd5\u5b8c\u6210\u5417\uff1f</p>\\n","title":"144. \u4e8c\u53c9\u6811\u7684\u524d\u5e8f\u904d\u5386","relatedTags":["\u6808","\u6811"],"difficult":"Easy","lang":["javascript"],"uniqueID":"144"}')}}]);